      appMechanic:'breathwork-overlay', appMechanicConfig:{ inhale:4, hold:1, exhale:6, cycles:3, activityLabel:'Between cycles: drop shoulders, reset grip to 4/10, take stance' },
      videoId:'PLACEHOLDER', videoChannel:'Cricket Mentor', videoTitle:'Between-Ball Routine — Calm Under Pressure',
