      baseline:'Complete the 30-ball short-ball challenge; score each ball 0–3 on quality.',
      measurement:'Average quality score per ball (0=poor, 1=acceptable, 2=good, 3=excellent) across 30 deliveries',
      masteryThreshold:'Average score of 2+ across 30 mixed short-ball deliveries',
      appMechanic:'simulation-script', appMechanicConfig:{ scenario:'30-ball short-ball test: partner varies height, width, and pace on all deliveries. Pull, hook, cut, duck, sway — all options available.', balls:30, resetOnWicket:false },
      videoId:'PLACEHOLDER', videoChannel:'Cricket Mentor', videoTitle:'Short Ball Mastery Test',
      outcome:'Short-pitched bowling becomes manageable — you select and execute the correct response automatically.',
      fit:{ roles:['opener','top-order','middle-order'], goals:['better-average','technical','mental-toughness'], ages:['u19','senior'], phases:['all'], surfaces:['all'], formats:['all'] },
      steps:['Partner delivers 30 varying short balls: some very short, some lifting, some wide, some straight','Apply the correct response to each: pull / hook / cut / sway / duck','Score each ball 0–3: 3 = executed perfectly, 0 = wrong decision or poor execution','Review: which delivery types produced the lowest scores?','Compare average across sessions — aim for consistent 2+ average','Consider mastered when consecutive 30-ball sets average 2+'],
