      appMechanic:'decision-tracker', appMechanicConfig:{ decisions:['bowl full outswing','bowl full inswing','use wobble seam'], balls:18, perBall:true },
      videoId:'PLACEHOLDER', videoChannel:'PitchVision', videoTitle:'Maximising Swing in Humid Conditions',
      outcome:'The bowler knows how to exploit humid conditions — maintaining ball condition and adjusting length to maximise movement.',
      fit:{ roles:['pace-opener','all-rounder'], goals:['technical','mental-toughness'], ages:['u19','senior'], phases:['first-30-overs','test-opening'], surfaces:['all'], formats:['test','odi','all'] },
