      baseline:'Bowl 20 stumps-line deliveries; how many hit the stumps (or would hit if not hit)?',
      measurement:'On-stump deliveries per 20 (would hit stumps if batter missed)',
      masteryThreshold:'12/20 deliveries hit (or would hit) the stumps',
      appMechanic:'lives-game', appMechanicConfig:{ lives:5, successTarget:12, resetOnFail:false },
      videoId:'PLACEHOLDER', videoChannel:'Cricket Australia', videoTitle:'Bowling at the Stumps',
