      videoId:'PLACEHOLDER', videoChannel:'Cricket Australia', videoTitle:'Wide Leg-Side Wicketkeeping',
      outcome:'Wide leg-side takes are clean — the footwork pattern is automatic and byes are eliminated.',
      fit:{ roles:['wicketkeeper'], goals:['technical','team-selection'], ages:['u15','u17','u19','senior'], phases:['all'], surfaces:['all'], formats:['all'] },
      steps:['Footwork: left foot steps sideways (not backward), right foot follows, take at extended position','Shadow 10 wide-leg takes without ball — feel the footwork','Add ball: 10 wide leg deliveries at medium pace','Audio cue triggers the left-foot step immediately','Count correct footwork takes (7 target)','Film from front to confirm foot positioning'],
      keyFocus:'Step sideways — do not cross the feet', commonError:'Right foot crossing in front of the left foot — creates instability and restricts reach',
