      videoId:'PLACEHOLDER', videoChannel:'Cricket Australia', videoTitle:'Single-Leg Stability for Cricket',
      outcome:'Improved single-leg stability prevents collapsing footwork in batting and creates a stable delivery platform for bowlers.',
      fit:{ roles:['opener','anchor','top-order','middle-order','pace-opener','pace-death','spinner','all-rounder','wicketkeeper'], goals:['fitness','technical','team-selection'], ages:['u13','u15','u17','u19','senior'], phases:['all'], surfaces:['all'], formats:['all'] },
