      appMechanic:'phase-timer', appMechanicConfig:{ phases:[{ label:'Internal Rotation', duration:90, target:'3 x 15 reps each shoulder (light band)' },{ label:'External Rotation', duration:90, target:'3 x 15 reps each shoulder' },{ label:'Scarecrow Rotation', duration:90, target:'3 x 10 reps — 90° elbow, rotate through range' }], restBetween:30 },
